### 2. Real-time Connection Management with API Gateway & WebSocket
While Linear might manage its own WebSocket servers, a common serverless WebSocket pattern uses API Gateway v2.

```typescript
// AWS Lambda handler for WebSocket connection routing
import { ApiGatewayManagementApiClient, PostToConnectionCommand } from "@aws-sdk/client-apigatewaymanagementapi";

const client = new ApiGatewayManagementApiClient({ endpoint: process.env.WS_ENDPOINT });

export const handler = async (event) => {
  const { routeKey, connectionId, body } = event.requestContext;

  switch (routeKey) {
    case "$connect":
      // Auth via query string, store connectionId in DynamoDB with user context
      await dynamodb.putItem({
        TableName: process.env.CONNECTIONS_TABLE,
        Item: { connectionId: { S: connectionId }, userId: { S: event.queryStringParameters?.userId } }
      });
      break;

    case "$disconnect":
      await dynamodb.deleteItem({
        TableName: process.env.CONNECTIONS_TABLE,
        Key: { connectionId: { S: connectionId } }
      });
      break;

    case "sendMessage":
      // Parse message, fan out to other user's connections
      const message = JSON.parse(body);
      const recipientConnections = await scanConnectionsForUser(message.recipientId);

      for (const conn of recipientConnections) {
        try {
          await client.send(new PostToConnectionCommand({
            ConnectionId: conn.connectionId,
            Data: Buffer.from(JSON.stringify(message))
          }));
        } catch (e) {
          if (e.statusCode === 410) { // Gone - stale connection
            await dynamodb.deleteItem({ TableName: process.env.CONNECTIONS_TABLE, Key: { connectionId: { S: conn.connectionId } } });
          }
        }
      }
      break;
  }

  return { statusCode: 200 };
};
```

### 3. Secure Secret & Configuration Management
Never hardcode secrets. Use AWS Systems Manager Parameter Store (for plaintext/config) and Secrets Manager (for rotation, RDS passwords).

```typescript
// At app startup, fetch parameters securely
import { SSMClient, GetParametersCommand } from "@aws-sdk/client-ssm";
import { SecretsManagerClient, GetSecretValueCommand } from "@aws-sdk/client-secrets-manager";

const ssm = new SSMClient({});
const secrets = new SecretsManagerClient({});

// Fetch non-sensitive configuration (e.g., feature flags, API endpoints)
const configParams = await ssm.send(new GetParametersCommand({
  Names: ["/app/featureFlags", "/app/externalApiUrl"],
  WithDecryption: false // Parameters stored as plaintext
}));

// Fetch sensitive database credentials
const secret = await secrets.send(new GetSecretValueCommand({
  SecretId: "prod/linear/postgres"
}));
const { host, port, username, password } = JSON.parse(secret.SecretString);
```

