### 2. Containerized Training Pipeline with SageMaker, ECR, and Step Functions
For robust, reproducible ML training workflows.

```python
# training_script.py (Runs inside SageMaker Container)
import argparse
import os
import pandas as pd
import joblib
from sklearn.ensemble import RandomForestRegressor
import boto3

# SageMaker passes hyperparameters as arguments
if __name__ == '__main__':
    parser = argparse.ArgumentParser()
    parser.add_argument('--n_estimators', type=int, default=100)
    parser.add_argument('--max_depth', type=int, default=10)
    parser.add_argument('--model-dir', type=str, default=os.environ.get('SM_MODEL_DIR'))
    parser.add_argument('--train', type=str, default=os.environ.get('SM_CHANNEL_TRAIN'))
    args = parser.parse_args()

    # Load data from SageMaker input channel
    train_data = pd.read_csv(os.path.join(args.train, 'train.csv'))
    X_train = train_data.drop('target', axis=1)
    y_train = train_data['target']

    # Train model
    model = RandomForestRegressor(
        n_estimators=args.n_estimators,
        max_depth=args.max_depth,
        random_state=42
    )
    model.fit(X_train, y_train)

    # Save model to SageMaker output directory
    joblib.dump(model, os.path.join(args.model_dir, 'model.joblib'))
